let agents = {}, routing = {}, events = [], analyticsData = {};
let refreshTimer = null;
let iconsCreated = false;

// Expose to inline handlers
window.updateRouting = updateRouting;

// ── Load Gateway Status ──────────────────────
async function loadGatewayStatus() {
  try {
    const { data, error } = await api('/api/system/status');
    const el = document.getElementById('gwStatusBar');
    if (error || !data) {
      el.innerHTML = '<div class="gw-dot unknown"></div><span class="gw-label">OpenClaw Gateway: Unknown</span><span class="gw-sub">System status API unavailable</span>';
      return;
    }
    const gw = data.gateway;
    const connected = gw?.status === 'connected';
    const cls = connected ? 'connected' : 'disconnected';
    const emoji = connected ? '🟢' : '🔴';
    const label = connected ? 'Connected' : 'Disconnected';
    el.innerHTML = `<div class="gw-dot ${cls}"></div><span class="gw-label">${emoji} OpenClaw Gateway: ${label}</span>`;
  } catch (e) {
    const el = document.getElementById('gwStatusBar');
    el.innerHTML = '<div class="gw-dot unknown"></div><span class="gw-label">OpenClaw Gateway: Unknown</span>';
  }
}

// ── Load All Data ──────────────────────
async function loadAll() {
  try {
    const [monRes, evRes, anRes] = await Promise.all([
      api('/api/monitor/agents'),
      api('/api/analytics/events?limit=50'),
      api('/api/analytics'),
      loadGatewayStatus()
    ]);

