const channels = [
  { id: 'whatsapp', label: 'WhatsApp', icon: 'message-circle', cls: 'wa' },
  { id: 'telegram', label: 'Telegram', icon: 'send', cls: 'tg' }
];
document.getElementById('routingBar').innerHTML = channels.map(ch => {
  const aid = routing[ch.id] || 'rafael';
  const agent = agents[aid];
  const options = Object.entries(agents)
    .sort((a, b) => (a[1].order || 0) - (b[1].order || 0))
    .map(([id, a]) => `<option value="${id}"${id === aid ? ' selected' : ''}>${escHtml(a.name)} — ${escHtml(a.role || '')}</option>`)
    .join('');
  return `<div class="route-card">
    <div class="route-icon ${ch.cls}"><i data-lucide="${ch.icon}"></i></div>
    <div>
      <div class="route-label">${ch.label} Handler</div>
      <div class="route-agent">${agent ? escHtml(agent.name) : escHtml(aid)}</div>
      <div style="font-size:9px;color:var(--text-tertiary);margin-top:2px">Default agent for MAGI ${ch.label} sends</div>
    </div>
    <select class="route-select" onchange="updateRouting('${ch.id}',this.value)">${options}</select>
  </div>`;
}).join('');

